export type Cell = [number, number];

const countLivingNeighbors = (cell: Cell, livingCells: Cell[]): number => {
  const [x, y] = cell;
  let count = 0;
  for (const [cx, cy] of livingCells) {
    if (cx === x && cy === y) continue;
    if (Math.abs(cx - x) <= 1 && Math.abs(cy - y) <= 1) count++;
  }
  return count;
};

export const nextGeneration = (livingCells: Cell[]): Cell[] => {
  return livingCells.filter((cell) => {
    const n = countLivingNeighbors(cell, livingCells);
    return n === 2 || n === 3;
  });
};

