export type Cell = [number, number];

const countLivingNeighbors = (cell: Cell, livingCells: Cell[]): number => {
  const [x, y] = cell;
  let count = 0;
  for (const [cx, cy] of livingCells) {
    if (cx === x && cy === y) continue;
    if (Math.abs(cx - x) <= 1 && Math.abs(cy - y) <= 1) count++;
  }
  return count;
};

const isLiving = (cell: Cell, livingCells: Cell[]): boolean => {
  const [x, y] = cell;
  return livingCells.some(([cx, cy]) => cx === x && cy === y);
};

export const nextGeneration = (livingCells: Cell[]): Cell[] => {
  const survivors = livingCells.filter((cell) => {
    const neighborCount = countLivingNeighbors(cell, livingCells);
    return neighborCount === 2 || neighborCount === 3;
  });

  const candidateDeadCells: Cell[] = [];
  for (const [x, y] of livingCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const candidate: Cell = [x + dx, y + dy];
        if (!isLiving(candidate, livingCells)) {
          candidateDeadCells.push(candidate);
        }
      }
    }
  }

  const births = candidateDeadCells.filter(
    (cell) => countLivingNeighbors(cell, livingCells) === 3
  );

  const result: Cell[] = [...survivors];
  for (const birth of births) {
    if (!isLiving(birth, result)) {
      result.push(birth);
    }
  }
  return result;
};

